        positions[idx + 3] = baseX + waveX - binormalX * width
        positions[idx + 4] = baseY + waveY - binormalY * width
        positions[idx + 5] = baseZ + waveZ - binormalZ * width

        // Set normals
        normals[idx] = normalX
