        side: side,
        stratum: stratum,
        flow: Math.random() * Math.PI * 2,
        oscillation: Math.random() * Math.PI * 2,
        velocity: 0.05 + stratum * 0.015,
        brightness: 0.6 + Math.random() * 0.4
      });
    }

    let time = 0;
    let isRunning = true;

