      // Clear canvas
      ctx.fillStyle = "#F0EEE6";
      ctx.fillRect(0, 0, width, height);

      // Group vertices by similar phi values to create "slices"
      const phiGroups = {};
      const phiPrecision = 0.2; // Grouping precision

      vertices.forEach((vertex, index) => {
        if (!isVisible[index]) return;

