        lineHeight: '12px',
        color: '#333333',
        cursor: 'none',
        overflow: 'hidden'
      }}
    >
      <pre style={{ margin: 0 }}>
        {asciiArt.map((line, i) => (
          <div key={i}>{line}</div>
        ))}
      </pre>
    </div>
  );
};

